    this.news = new CoinankNews(_client)
    this.indicator = new CoinankIndicator(_client)
    this.oi = new CoinankOi(_client)
    this.rank = new CoinankRank(_client)
    this.liquidation = new CoinankLiquidation(_client)
    this.orderbook = new CoinankOrderbook(_client)
    this.fund = new CoinankFund(_client)
    this.orderFlow = new CoinankOrderFlow(_client)
    this.fundingRate = new CoinankFundingRate(_client)
    this.rsi = new CoinankRsi(_client)
